CREATE VIEW public.vw_pbi_mora AS
 SELECT rc.id AS caso_mora_id,
    rc.credit_application_id AS solicitud_id,
    rc.user_id AS cliente_id,
    u.full_name AS cliente_nombre,
    c.product AS producto,
    c.amount AS monto_credito,
    rc.overdue_amount AS monto_mora,
    rc.days_past_due AS dias_mora,
    rc.band AS banda_mora,
    rc.status AS estado_mora,
    au.full_name AS asignado_a,
    au.position_name AS cargo_asignado,
    rc.created_at AS fecha_creacion,
    rc.updated_at AS fecha_actualizacion,
    (EXTRACT(year FROM rc.created_at))::integer AS anio
   FROM (((public.recovery_case rc
     JOIN public."user" u ON ((u.id = rc.user_id)))
     JOIN public.creditapplication c ON ((c.id = rc.credit_application_id)))
     LEFT JOIN public.core_analyst_user au ON ((au.id = rc.assigned_to)));


ALTER VIEW public.vw_pbi_mora OWNER TO postgres;

--
-- Name: vw_pbi_operaciones_banbif; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_pbi_operaciones_banbif AS
 SELECT 'Transaccion'::text AS modulo,
    m.id AS operacion_id,
    u.id AS cliente_id,
    u.full_name AS cliente_nombre,
    m.operation_type AS tipo,
    m.description AS descripcion,
    m.amount AS monto,
    'Registrado'::character varying AS estado,
    m.created_at AS fecha,
    (EXTRACT(year FROM m.created_at))::integer AS anio,
    to_char(m.created_at, 'YYYY-MM'::text) AS anio_mes
   FROM ((public.movement m
     JOIN public.account a ON ((a.id = m.account_id)))
     JOIN public."user" u ON ((u.id = a.user_id)))
UNION ALL
 SELECT 'Pago'::text AS modulo,
    p.id AS operacion_id,
    u.id AS cliente_id,
    u.full_name AS cliente_nombre,
    p.servicio AS tipo,
    p.numero_contrato AS descripcion,
    p.monto,
    p.estado,
    p.created_at AS fecha,
    (EXTRACT(year FROM p.created_at))::integer AS anio,
    to_char(p.created_at, 'YYYY-MM'::text) AS anio_mes
   FROM (public.pagos p
     JOIN public."user" u ON ((u.id = p.user_id)))
UNION ALL
 SELECT 'Credito'::text AS modulo,
    c.id AS operacion_id,
    u.id AS cliente_id,
    u.full_name AS cliente_nombre,
    c.product AS tipo,
    c.purpose AS descripcion,
    c.amount AS monto,
    c.status AS estado,
    c.created_at AS fecha,
    (EXTRACT(year FROM c.created_at))::integer AS anio,
    to_char(c.created_at, 'YYYY-MM'::text) AS anio_mes
   FROM (public.creditapplication c
     JOIN public."user" u ON ((u.id = c.user_id)))
UNION ALL
 SELECT 'Mora'::text AS modulo,
    rc.id AS operacion_id,
    u.id AS cliente_id,
    u.full_name AS cliente_nombre,
    rc.band AS tipo,
    rc.status AS descripcion,
    rc.overdue_amount AS monto,
    rc.status AS estado,
    rc.created_at AS fecha,
    (EXTRACT(year FROM rc.created_at))::integer AS anio,
    to_char(rc.created_at, 'YYYY-MM'::text) AS anio_mes
   FROM (public.recovery_case rc
     JOIN public."user" u ON ((u.id = rc.user_id)));


ALTER VIEW public.vw_pbi_operaciones_banbif OWNER TO postgres;

--
-- Name: vw_pbi_pagos; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_pbi_pagos AS
 SELECT p.id AS pago_id,
    p.user_id AS cliente_id,
    u.full_name AS cliente_nombre,
    p.account_id AS cuenta_id,
    a.account_number AS numero_cuenta,
    p.servicio,
    p.numero_contrato AS contrato,
    p.monto AS monto_pagado,
    p.estado AS estado_pago,
    p.created_at AS fecha_pago,
    (EXTRACT(year FROM p.created_at))::integer AS anio,
    (EXTRACT(month FROM p.created_at))::integer AS mes,
    to_char(p.created_at, 'YYYY-MM'::text) AS anio_mes
   FROM ((public.pagos p
     JOIN public."user" u ON ((u.id = p.user_id)))
     LEFT JOIN public.account a ON ((a.id = p.account_id)));


ALTER VIEW public.vw_pbi_pagos OWNER TO postgres;

--
-- Name: vw_pbi_resumen_general; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_pbi_resumen_general AS
 SELECT u.id AS cliente_id,
    u.full_name AS cliente_nombre,
    count(DISTINCT a.id) AS total_cuentas,
    COALESCE(sum(DISTINCT a.balance), (0)::double precision) AS saldo_total,
    count(DISTINCT m.id) AS total_transacciones,
    count(DISTINCT p.id) AS total_pagos,
    count(DISTINCT c.id) AS total_creditos,
    count(DISTINCT d.id) AS total_desembolsos,
    count(DISTINCT rc.id) AS total_casos_mora
   FROM ((((((public."user" u
     LEFT JOIN public.account a ON ((a.user_id = u.id)))
     LEFT JOIN public.movement m ON ((m.account_id = a.id)))
     LEFT JOIN public.pagos p ON ((p.user_id = u.id)))
     LEFT JOIN public.creditapplication c ON ((c.user_id = u.id)))
     LEFT JOIN public.credit_disbursement d ON ((d.credit_application_id = c.id)))
     LEFT JOIN public.recovery_case rc ON ((rc.user_id = u.id)))
  GROUP BY u.id, u.full_name;


ALTER VIEW public.vw_pbi_resumen_general OWNER TO postgres;

--
-- Name: vw_pbi_roles_core; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_pbi_roles_core AS
 SELECT au.id AS usuario_core_id,
    au.full_name AS nombre,
    au.username,
    au.role AS rol,
    au.position_name AS cargo,
    au.approval_level AS nivel_aprobacion,
    au.max_approval_amount AS monto_maximo_aprobacion,
    au.is_active AS activo,
    count(rp.permission_code) AS total_permisos
   FROM (public.core_analyst_user au
     LEFT JOIN public.core_role_permission rp ON (((rp.role)::text = (au.role)::text)))
  GROUP BY au.id, au.full_name, au.username, au.role, au.position_name, au.approval_level, au.max_approval_amount, au.is_active;


ALTER VIEW public.vw_pbi_roles_core OWNER TO postgres;

--
-- Name: vw_pbi_transacciones; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_pbi_transacciones AS
 SELECT m.id AS transaccion_id,
    a.user_id AS cliente_id,
    u.full_name AS cliente_nombre,
    a.id AS cuenta_id,
    a.account_number AS numero_cuenta,
    m.operation_type AS tipo_operacion,
    m.description AS descripcion,
    m.amount AS monto,
    m.created_at AS fecha,
    (EXTRACT(year FROM m.created_at))::integer AS anio,
    (EXTRACT(month FROM m.created_at))::integer AS mes,
    to_char(m.created_at, 'YYYY-MM'::text) AS anio_mes
   FROM ((public.movement m
     JOIN public.account a ON ((a.id = m.account_id)))
     JOIN public."user" u ON ((u.id = a.user_id)));


ALTER VIEW public.vw_pbi_transacciones OWNER TO postgres;

